def majority_element_ii(nums: list[int]) -> list[int]:
    if not nums:
        return []

    candidate1, candidate2 = 0, 0
    count1, count2 = 0, 0

    for num in nums:
        if num == candidate1:
            count1 += 1
        elif num == candidate2:
            count2 += 1
        elif count1 == 0:
            candidate1 = num
            count1 = 1
        elif count2 == 0:
            candidate2 = num
            count2 = 1
        else:
            count1 -= 1
            count2 -= 1

    count1_actual, count2_actual = 0, 0
    for num in nums:
        if num == candidate1:
            count1_actual += 1
        elif num == candidate2:
            count2_actual += 1

    result = set()
    n = len(nums)

    if count1_actual > n / 3:
        result.add(candidate1)

    if count2_actual > n / 3:
        result.add(candidate2)

    return list(result)
